const fs = require('fs');
let lines = [];
try { lines = fs.readFileSync('/config/energy-sources.txt','utf8').split(/\r?\n/); } catch (e) {}
const urls = lines.map(function(l){ return l.trim(); }).filter(function(l){ return l && l.charAt(0) !== '#'; });
if (!urls.length) { return [{ json: { url: '' } }]; }
return urls.map(function(u){ return { json: { url: u } }; });

const items = $input.all();
const arts = items.map(function(i){ return i.json; }).filter(function(a){ return a && (a.title || a.contentSnippet || a.content); });
const companies = [
  ['ADNOC', /adnoc|borouge|ta.?ziz|upper zakum|\bxrg\b/i],
  ['Saudi Aramco', /aramco/i],
  ['QatarEnergy', /qatarenergy|qatar energy/i],
  ['Kuwait Petroleum', /kuwait petroleum|\bkpc\b|kuwait oil/i],
  ['TAQA / Masdar / Mubadala', /\btaqa\b|masdar|mubadala/i],
  ['Shell', /\bshell\b/i],
  ['BP', /\bbp\b/i],
  ['Chevron', /chevron/i],
  ['ExxonMobil', /exxon/i],
  ['TotalEnergies', /totalenergies|total energies/i]
];
function detect(a){ var s=((a.title||'')+' '+(a.contentSnippet||a.content||'')).toString(); for(var i=0;i<companies.length;i++){ if(companies[i][1].test(s)) return companies[i][0]; } return 'Other'; }
function getImg(a){ try { if(a.enclosure && a.enclosure.url) return a.enclosure.url; var mc=a['media:content']||a.mediaContent; if(mc){ if(Array.isArray(mc)) mc=mc[0]; if(mc){ if(mc.url) return mc.url; if(mc['$'] && mc['$'].url) return mc['$'].url; } } var mt=a['media:thumbnail']||a.mediaThumbnail; if(mt){ if(Array.isArray(mt)) mt=mt[0]; if(mt){ if(mt.url) return mt.url; if(mt['$'] && mt['$'].url) return mt['$'].url; } } var c=(a.content||a['content:encoded']||'').toString(); var m=c.match(/<img[^>]+src=["']([^"']+)["']/i); if(m) return m[1]; } catch(e){} return ''; }
function fmt(a){ var t=(a.title||'').toString(); var s=(a.contentSnippet||a.content||'').toString().replace(/\s+/g,' ').slice(0,200); var u=(a.link||a.url||'').toString(); var im=getImg(a); return '- ' + t + ' — ' + s + ' (' + u + ')' + (im?(' IMG='+im):''); }
var buckets={};
arts.forEach(function(a){ var k=detect(a); (buckets[k]=buckets[k]||[]).push(a); });
var order=Object.keys(buckets);
var perCompany=4; var lines=[];
for(var r=0;r<perCompany;r++){ for(var c=0;c<order.length;c++){ var arr=buckets[order[c]]; if(arr[r]){ lines.push('['+order[c]+'] '+fmt(arr[r])); } } }
var text = lines.length ? lines.join('\n') : 'No source articles were retrieved this period.';
var previous='';
try {
  var fs=require('fs'); var dir='/reports/archive/energy-intelligence';
  var today=new Date().toISOString().slice(0,10);
  var files=fs.readdirSync(dir).filter(function(fn){ return /energy-intelligence-\d{4}-\d{2}-\d{2}\.json$/.test(fn) && fn.indexOf(today)===-1; }).sort();
  if(files.length){
    var prev=JSON.parse(fs.readFileSync(dir+'/'+files[files.length-1],'utf8'));
    var ple=[];
    ['noc','ioc'].forEach(function(sec){ (prev[sec]||[]).forEach(function(row){ ple.push('- '+(row.company||'')+': '+((row.development||'').toString().slice(0,160))); }); });
    previous='From '+files[files.length-1].replace('energy-intelligence-','').replace('.json','')+':\n'+ple.join('\n');
  }
} catch(e){ previous=''; }
return [{ json: { articles: text, count: arts.length, date: new Date().toISOString().slice(0,10), previous: previous } }];

