const j = $json || {};
let md = '';
if (j.message && j.message.content) { md = j.message.content; }
else if (j.content && j.content[0] && j.content[0].text) { md = j.content[0].text; }
else if (typeof j.markdown === 'string') { md = j.markdown; }
md = md || '';
const top = md.split(/\n/).filter(function(l){ return /adnoc|energy|oil|gas|lng|masdar|taqa/i.test(l); }).slice(0,4).join('; ') || 'UAE and ADNOC energy sector developments';
const style = 'Premium editorial intelligence-report cover. Deep navy (#0A1A2F) background with refined gold (#C9A24B) accents. Abstract professional energy motifs. NO text, NO logos, NO faces.';
return [{ json: { markdown: md || 'No data available for this period.', date: new Date().toISOString().slice(0,10), coverPrompt: style + ' Visual theme inspired by: ' + top } }];

let raw = ($json && $json.markdown) || '';
let data = null;
try { data = JSON.parse(raw); } catch (e) {
  try { var m = raw.match(/\{[\s\S]*\}/); if (m) { data = JSON.parse(m[0]); } } catch (e2) { data = null; }
}
const date = ($json && $json.date) || new Date().toISOString().slice(0,10);
const fs = require('fs');
function imgDataUri(base){
  var tries = [['/config/branding/'+base+'.png','image/png'], ['/config/branding/'+base+'.jpg','image/jpeg'], ['/config/branding/'+base+'.jpeg','image/jpeg']];
  for (var i=0;i<tries.length;i++){ try { var b = fs.readFileSync(tries[i][0]); return 'data:'+tries[i][1]+';base64,'+b.toString('base64'); } catch (e) {} }
  return '';
}
// Build logo map from config/branding/logos/<key>.(png|jpg)
var logoMap = {};
try {
  var files = fs.readdirSync('/config/branding/logos');
  files.forEach(function(fn){
    var mt = fn.match(/^(.+)\.(png|jpe?g)$/i);
    if (!mt) return;
    var key = mt[1].toLowerCase();
    var mime = /png$/i.test(fn) ? 'image/png' : 'image/jpeg';
    try { logoMap[key] = 'data:'+mime+';base64,'+fs.readFileSync('/config/branding/logos/'+fn).toString('base64'); } catch (e) {}
  });
} catch (e) {}
function logoFor(company){
  var c = (company||'').toLowerCase().replace(/[^a-z0-9]/g,'');
  var keys = Object.keys(logoMap);
  for (var i=0;i<keys.length;i++){ if (c.indexOf(keys[i]) !== -1) return logoMap[keys[i]]; }
  return '';
}
const coverSrc = imgDataUri('cover');
const bannerSrc = imgDataUri('banner');
const avatarSrc = imgDataUri('jarvis-avatar');
let heroImg=''; try { var hb=$('Generate Cover (Image Provider)').first().json.data[0].b64_json; if(hb){ heroImg='<img src="data:image/png;base64,'+hb+'" style="width:100%;display:block"/>'; } } catch(e){ heroImg=''; }
function ord(n){ var s=['th','st','nd','rd'], v=n%100; return n + (s[(v-20)%10] || s[v] || s[0]); }
function prettyDate(d){ try { var p=(d||'').split('-'); var dt=new Date(Number(p[0]),Number(p[1])-1,Number(p[2])); var M=['January','February','March','April','May','June','July','August','September','October','November','December']; return M[dt.getMonth()]+' '+ord(dt.getDate())+' '+dt.getFullYear(); } catch(e){ return d; } }
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g, function(c){ return ({ '&':'&amp;', '<':'&lt;', '>':'&gt;' })[c]; }); }
function riskColor(r){ r=(r||'').toString().toLowerCase(); if(r.indexOf('high')===0) return '#B02525'; if(r.indexOf('med')===0) return '#B8860B'; if(r.indexOf('low')===0) return '#1E8E5A'; return '#5A6472'; }
function companyCell(company){
  var l = logoFor(company);
  var img = l ? ('<img src="'+l+'" style="height:22px;width:auto;vertical-align:middle;margin-right:6px"/>') : '';
  return '<td style="padding:8px;font-weight:600;white-space:nowrap">'+img+esc(company)+'</td>';
}
function devCards(rows){
  if(!rows || !rows.length) return '<p style="color:#5A6472">No data available for this period.</p>';
  return rows.map(function(r){
    var l = (typeof logoFor==='function') ? logoFor(r.company) : '';
    var img = l ? ('<img src="'+l+'" style="height:26px;width:auto;vertical-align:middle;margin-right:8px"/>') : '';
    return '<div style="border:1px solid #E2E6EC;border-left:4px solid #2E9BE6;border-radius:6px;padding:12px 14px;margin:12px 0;page-break-inside:avoid">'
      + '<div style="font-family:Georgia,serif;font-size:16px;color:#0A1A2F;font-weight:700;margin-bottom:6px">'+img+esc(r.company)+'</div>'
      + '<p style="margin:5px 0;font-size:14px;line-height:1.5"><strong>Key Development:</strong> '+esc(r.development)+'</p>'
      + '<p style="margin:5px 0;font-size:14px;line-height:1.5"><strong>Strategic Theme:</strong> '+esc(r.theme)+'</p>'
      + '<p style="margin:5px 0;font-size:14px;line-height:1.5"><strong>What It Signals:</strong> '+esc(r.signals)+'</p>'
      + '<p style="margin:5px 0;font-size:14px;line-height:1.5"><strong>Market Impact / Risk:</strong> <span style="color:'+riskColor(r.risk)+';font-weight:600">'+esc(r.risk)+'</span></p>'
      + '<p style="margin:5px 0;font-size:14px;line-height:1.5"><strong>Watch Point:</strong> '+esc(r.watch)+'</p>'
      + '</div>';
  }).join('');
}
function devTable(rows){
  if(!rows || !rows.length) return '<p style="color:#5A6472">No data available for this period.</p>';
  var th = '<tr style="background:#0A1A2F;color:#FFFFFF">' + ['Company','Key Development','Strategic Theme','What It Signals','Market Impact / Risk','Watch Point'].map(function(h){ return '<th style="padding:8px;text-align:left;font-size:12px">'+h+'</th>'; }).join('') + '</tr>';
  var trs = rows.map(function(r){ return '<tr style="border-bottom:1px solid #E2E6EC;vertical-align:top">' +
    companyCell(r.company) +
    '<td style="padding:8px">'+esc(r.development)+'</td>' +
    '<td style="padding:8px">'+esc(r.theme)+'</td>' +
    '<td style="padding:8px">'+esc(r.signals)+'</td>' +
    '<td style="padding:8px;color:'+riskColor(r.risk)+';font-weight:600">'+esc(r.risk)+'</td>' +
    '<td style="padding:8px;font-style:italic">'+esc(r.watch)+'</td></tr>'; }).join('');
  return '<table style="border-collapse:collapse;width:100%;font-size:13px;margin:8px 0">'+th+trs+'</table>';
}
function moversTable(rows){
  if(!rows || !rows.length) return '<p style="color:#5A6472">No notable leadership changes this period.</p>';
  var th = '<tr style="background:#0A1A2F;color:#FFFFFF">' + ['Company','Individual','Previous role','New role','Effective','Why it matters'].map(function(h){ return '<th style="padding:8px;text-align:left;font-size:12px">'+h+'</th>'; }).join('') + '</tr>';
  var trs = rows.map(function(r){ return '<tr style="border-bottom:1px solid #E2E6EC;vertical-align:top">' +
    companyCell(r.company) +
    '<td style="padding:8px">'+esc(r.individual)+'</td>' +
    '<td style="padding:8px">'+esc(r.previous)+'</td>' +
    '<td style="padding:8px">'+esc(r.current)+'</td>' +
    '<td style="padding:8px">'+esc(r.date)+'</td>' +
    '<td style="padding:8px;font-style:italic">'+esc(r.why)+'</td></tr>'; }).join('');
  return '<table style="border-collapse:collapse;width:100%;font-size:13px;margin:8px 0">'+th+trs+'</table>';
}
function h2(t){ return '<h2 style="color:#0A1A2F;border-left:4px solid #2E9BE6;padding-left:10px;font-family:Georgia,serif;font-size:18px;margin-top:28px;border-bottom:1px solid #E2E6EC;padding-bottom:6px">'+t+'</h2>'; }
function leadPara(t){ t=(t||'').toString(); if(!t) return ''; var f=esc(t.charAt(0)); var rest=esc(t.slice(1)); return '<p style="font-size:15.5px;line-height:1.7;color:#11151c"><span style="float:left;font-family:Georgia,serif;font-size:48px;line-height:40px;padding:2px 10px 0 0;color:#2E9BE6;font-weight:700">'+f+'</span>'+rest+'</p>'; }
function features(rows){ if(!rows||!rows.length) return ''; return rows.map(function(s){ var src=(s.source||'').toString(); var im=(s.image||'').toString(); var imgTag=/^https?:\/\//.test(im)?('<img src="'+im+'" style="width:100%;max-height:240px;object-fit:cover;border-radius:4px;margin:2px 0 8px"/>'):''; var link=/^https?:\/\//.test(src)?('<a href="'+src+'" style="color:#2E9BE6;text-decoration:none;font-size:13px">Read the source &rsaquo;</a>'):(src?('<span style="color:#5A6472;font-size:13px">Source: '+esc(src)+'</span>'):''); return '<div style="border-left:4px solid #2E9BE6;padding:4px 0 8px 14px;margin:16px 0;page-break-inside:avoid">'+imgTag+'<div style="font-family:Georgia,serif;font-size:19px;font-weight:700;color:#0A1A2F;margin-bottom:5px">'+esc(s.headline)+'</div><p style="font-size:14.5px;line-height:1.65;margin:4px 0">'+esc(s.story)+'</p>'+link+'</div>'; }).join(''); }
let body;
if (data) {
  var bonus = data.bonus || {};
  body = leadPara(data.intro) + (data.weekOverWeek ? ('<div style="background:#EAF4FC;border-left:4px solid #2E9BE6;padding:10px 12px;margin:12px 0;font-size:14px"><strong>What changed since last edition:</strong> '+esc(data.weekOverWeek)+'</div>') : '') +
    ((data.featured && data.featured.length) ? (h2('Featured Stories') + features(data.featured)) : '') + h2('This week — Middle East NOCs') + devCards(data.noc) +
    h2('This week — Supermajor IOCs') + devCards(data.ioc) +
    h2('Movers &amp; Shakers') + moversTable(data.movers) +
    h2('Bonus Read' + (bonus.title ? (': ' + esc(bonus.title)) : '')) +
    '<div style="font-size:14px;line-height:1.6">'+esc(bonus.body||'').replace(/\n/g,'<br/>')+'</div>';
} else {
  body = '<div style="padding:12px;background:#FDECEC;border:1px solid #B02525;color:#7a1a1a;border-radius:4px">The analyst did not return structured data this run. Raw output below.</div><pre style="white-space:pre-wrap;font-family:inherit">'+esc(raw)+'</pre>';
}
const weekOf = (data && data.weekOf) ? data.weekOf : date;
const frontCover = coverSrc ? ('<div style="position:relative;height:100vh;page-break-after:always;overflow:hidden">' + '<img src="'+coverSrc+'" style="width:100%;height:100%;object-fit:cover;display:block"/>' + '<div style="position:absolute;top:26px;right:30px;color:#FFFFFF;font-family:Georgia,serif;font-size:22px;font-weight:700;text-shadow:0 1px 5px rgba(0,0,0,0.7)">'+esc(prettyDate(date))+'</div>' + '</div>') : '';
const masthead = bannerSrc ? ('<img src="'+bannerSrc+'" style="width:100%;display:block"/>') : ('<div style="background:#0A1A2F;color:#FFFFFF;padding:18px;font-family:Georgia,serif;font-size:20px">JARVIS INTELLIGENCE — Weekly Energy Intelligence Brief</div>');
const signoff = avatarSrc ? ('<div style="text-align:center;padding:20px;border-top:3px solid #2E9BE6;margin-top:16px"><img src="'+avatarSrc+'" style="width:104px;height:104px;border-radius:50%;border:2px solid #2E9BE6"/><div style="font-family:Georgia,serif;color:#0A1A2F;margin-top:8px;font-size:14px">Jarvis — AI News Reporter</div></div>') : '';
const html = '<!doctype html><meta charset="utf-8"><title>Energy Intelligence Brief — '+esc(weekOf)+'</title>' +
  '<div style="font-family:-apple-system,Segoe UI,Arial,sans-serif;color:#11151c;max-width:980px;margin:0 auto">' +
  frontCover + masthead +
  '<div style="background:#05101F;color:#cdd5e0;padding:6px 18px;font-size:13px">'+esc(weekOf)+' &nbsp;·&nbsp; Confidential</div>' + heroImg +
  '<div style="padding:28px">'+body+'</div>' +
  signoff + '</div>';
return [{ json: { date: date, html: html, markdown: raw } }];

const fs = require('fs');
const date = $json.date;
const html = $json.html;
const md = $json.markdown || '';
const dirs = ['/reports/energy-intelligence', '/reports/archive/energy-intelligence'];
for (var k = 0; k < dirs.length; k++) {
  try { fs.mkdirSync(dirs[k], { recursive: true }); fs.writeFileSync(dirs[k] + '/energy-intelligence-' + date + '.html', html); } catch (e) {}
}
try { fs.writeFileSync('/reports/archive/energy-intelligence/energy-intelligence-' + date + '.json', md); } catch (e) {}
try { fs.writeFileSync('/logs/last-run-success.txt', new Date().toISOString() + ' energy-intelligence'); } catch (e) {}
return [{ json: $json }];

