const fs = require('fs');
let lines = [];
try { lines = fs.readFileSync('/config/energy-movers-sources.txt','utf8').split(/\r?\n/); } catch (e) {}
const urls = lines.map(function(l){ return l.trim(); }).filter(function(l){ return l && l.charAt(0) !== '#'; });
if (!urls.length) { return [{ json: { url: '' } }]; }
return urls.map(function(u){ return { json: { url: u } }; });

const items = $input.all();
const arts = items.map(function(i){ return i.json; }).filter(function(a){ return a && (a.title || a.contentSnippet || a.content); });
const lines = arts.slice(0,18).map(function(a){
  var t = (a.title||'').toString();
  var s = (a.contentSnippet||a.content||'').toString().replace(/\s+/g,' ').slice(0,220);
  var u = (a.link||a.url||'').toString();
  return '- ' + t + ' — ' + s + ' (' + u + ')';
});
const text = lines.length ? lines.join('\n') : 'No leadership-change articles retrieved.';
return [{ json: { moversDigest: text, moversCount: arts.length } }];

const date = $json.date;
const html = $json.html;
const footer = '<!doctype html><html><head><meta charset="utf-8"></head><body style="margin:0;padding:0">'
 + '<div style="font-size:9px;color:#5A6472;font-family:Arial,Helvetica,sans-serif;width:100%;box-sizing:border-box;padding:0 14mm;display:flex;justify-content:space-between;align-items:center">'
 + '<span>JARVIS INTELLIGENCE &nbsp;&middot;&nbsp; AI-generated &mdash; always verify findings</span>'
 + '<span>Page <span class="pageNumber"></span> of <span class="totalPages"></span></span>'
 + '</div></body></html>';
return [{ json: { date: date },
  binary: {
    data:   { data: Buffer.from(html,'utf8').toString('base64'),   mimeType: 'text/html', fileName: 'index.html' },
    footer: { data: Buffer.from(footer,'utf8').toString('base64'), mimeType: 'text/html', fileName: 'footer.html' }
  } }];
